CREATE TABLE "work_schedules" ("id" UUID NOT NULL DEFAULT gen_random_uuid(), "company_id" UUID NOT NULL, "code" VARCHAR(50) NOT NULL, "name" VARCHAR(160) NOT NULL, "weekly_minutes" INTEGER NOT NULL, "status" VARCHAR(20) NOT NULL DEFAULT 'ACTIVE', "created_at" TIMESTAMPTZ(6) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMPTZ(6) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "work_schedules_pkey" PRIMARY KEY ("id"), CONSTRAINT "work_schedules_minutes_check" CHECK ("weekly_minutes" > 0));
CREATE TABLE "work_schedule_periods" ("id" UUID NOT NULL DEFAULT gen_random_uuid(), "work_schedule_id" UUID NOT NULL, "weekday" INTEGER NOT NULL, "start_minute" INTEGER NOT NULL, "end_minute" INTEGER NOT NULL, "break_minutes" INTEGER NOT NULL DEFAULT 0, "created_at" TIMESTAMPTZ(6) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "work_schedule_periods_pkey" PRIMARY KEY ("id"), CONSTRAINT "work_schedule_periods_weekday_check" CHECK ("weekday" BETWEEN 0 AND 6), CONSTRAINT "work_schedule_periods_time_check" CHECK ("start_minute" >= 0 AND "end_minute" > "start_minute" AND "end_minute" <= 1440 AND "break_minutes" >= 0));
CREATE TABLE "contract_work_schedules" ("id" UUID NOT NULL DEFAULT gen_random_uuid(), "employment_contract_id" UUID NOT NULL, "work_schedule_id" UUID NOT NULL, "valid_from" DATE NOT NULL, "valid_to" DATE, "reason" VARCHAR(500), "created_at" TIMESTAMPTZ(6) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "contract_work_schedules_pkey" PRIMARY KEY ("id"));
CREATE TABLE "holidays" ("id" UUID NOT NULL DEFAULT gen_random_uuid(), "company_id" UUID, "holiday_date" DATE NOT NULL, "name" VARCHAR(160) NOT NULL, "scope" VARCHAR(20) NOT NULL DEFAULT 'COMPANY', "created_at" TIMESTAMPTZ(6) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "holidays_pkey" PRIMARY KEY ("id"));
CREATE TABLE "time_entries" ("id" UUID NOT NULL DEFAULT gen_random_uuid(), "employment_contract_id" UUID NOT NULL, "company_id" UUID NOT NULL, "occurred_on" DATE NOT NULL, "type" VARCHAR(30) NOT NULL, "minutes" INTEGER NOT NULL, "source" VARCHAR(30) NOT NULL DEFAULT 'MANUAL', "status" VARCHAR(20) NOT NULL DEFAULT 'PENDING', "reason" VARCHAR(1000), "created_at" TIMESTAMPTZ(6) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "time_entries_pkey" PRIMARY KEY ("id"));
CREATE TABLE "time_balance_entries" ("id" UUID NOT NULL DEFAULT gen_random_uuid(), "employment_contract_id" UUID NOT NULL, "time_entry_id" UUID, "occurred_on" DATE NOT NULL, "minutes" INTEGER NOT NULL, "type" VARCHAR(30) NOT NULL, "reason" VARCHAR(1000), "created_at" TIMESTAMPTZ(6) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "time_balance_entries_pkey" PRIMARY KEY ("id"));
CREATE TABLE "time_balance_closings" ("id" UUID NOT NULL DEFAULT gen_random_uuid(), "company_id" UUID NOT NULL, "reference_month" DATE NOT NULL, "status" VARCHAR(20) NOT NULL DEFAULT 'OPEN', "closed_at" TIMESTAMPTZ(6), "reason" VARCHAR(1000), "created_at" TIMESTAMPTZ(6) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "time_balance_closings_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "work_schedules_company_code_key" ON "work_schedules"("company_id", "code"); CREATE UNIQUE INDEX "work_schedule_periods_schedule_day_start_key" ON "work_schedule_periods"("work_schedule_id", "weekday", "start_minute"); CREATE UNIQUE INDEX "contract_work_schedules_contract_start_key" ON "contract_work_schedules"("employment_contract_id", "valid_from"); CREATE UNIQUE INDEX "holidays_company_date_name_key" ON "holidays"("company_id", "holiday_date", "name"); CREATE UNIQUE INDEX "time_balance_closings_company_month_key" ON "time_balance_closings"("company_id", "reference_month"); CREATE INDEX "time_entries_contract_date_idx" ON "time_entries"("employment_contract_id", "occurred_on"); CREATE INDEX "time_balance_entries_contract_date_idx" ON "time_balance_entries"("employment_contract_id", "occurred_on");
ALTER TABLE "work_schedules" ADD CONSTRAINT "work_schedules_company_fkey" FOREIGN KEY ("company_id") REFERENCES "companies"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "work_schedule_periods" ADD CONSTRAINT "work_schedule_periods_schedule_fkey" FOREIGN KEY ("work_schedule_id") REFERENCES "work_schedules"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "contract_work_schedules" ADD CONSTRAINT "contract_work_schedules_contract_fkey" FOREIGN KEY ("employment_contract_id") REFERENCES "employment_contracts"("id") ON DELETE RESTRICT ON UPDATE CASCADE, ADD CONSTRAINT "contract_work_schedules_schedule_fkey" FOREIGN KEY ("work_schedule_id") REFERENCES "work_schedules"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "holidays" ADD CONSTRAINT "holidays_company_fkey" FOREIGN KEY ("company_id") REFERENCES "companies"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "time_entries" ADD CONSTRAINT "time_entries_contract_fkey" FOREIGN KEY ("employment_contract_id") REFERENCES "employment_contracts"("id") ON DELETE RESTRICT ON UPDATE CASCADE, ADD CONSTRAINT "time_entries_company_fkey" FOREIGN KEY ("company_id") REFERENCES "companies"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "time_balance_entries" ADD CONSTRAINT "time_balance_entries_contract_fkey" FOREIGN KEY ("employment_contract_id") REFERENCES "employment_contracts"("id") ON DELETE RESTRICT ON UPDATE CASCADE, ADD CONSTRAINT "time_balance_entries_time_entry_fkey" FOREIGN KEY ("time_entry_id") REFERENCES "time_entries"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "time_balance_closings" ADD CONSTRAINT "time_balance_closings_company_fkey" FOREIGN KEY ("company_id") REFERENCES "companies"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
